    94→
    95→impl Default for CoordinateDescentConfig {
    96→    fn default() -> Self {
    97→        Self {
    98→            max_iter: 1000,
    99→            tolerance: 1e-7,
   100→            lambda: 0.01,
   101→            alpha: 1.0,
